  /**
   * Provides culture specific map labels. For more information visit:
   * https://learn.microsoft.com/en-us/bingmaps/rest-services/common-parameters-and-types/culture-parameter
   *
   * For a list of supported culture codes please visit:
   * https://learn.microsoft.com/en-us/bingmaps/rest-services/common-parameters-and-types/supported-culture-codes
   *
   * @default "en-US"
   * @example
   * // To change the default culture.
   * let bing = new BingMapsLayer({
   *   key: "~~~~~~~~~~~~~~~~~~~~~~~~ Bing maps key ~~~~~~~~~~~~~~~~~~~~~~~~~",
   *   culture: "fr"
   * });
   */
  accessor culture: BingMapsCulture;
  /**
   * Indicates if the layer has attribution data.
   *
   * @default true
   */
  get hasAttributionData(): boolean;
  /**
   * Bing Maps Key.
   *
   * @example
   * // At minimum, a valid Bing key is required to create a Bing maps layer.
   * let bing = new BingMapsLayer({
   *   key: "~~~~~~~~~~~~~~~~~~~~~~~~ Bing maps key ~~~~~~~~~~~~~~~~~~~~~~~~~"
   * });
   */
  accessor key: string;
  /**
   * This will alter Geopolitical disputed borders and labels to align with the specified user region.
   *
   * For more information on Bing's region setting please visit:
   * https://learn.microsoft.com/en-us/bingmaps/rest-services/common-parameters-and-types/user-context-parameters
   *
   * For a list of supported country codes please visit:
   * see https://en.wikipedia.org/wiki/ISO_3166-1_alpha-2
   *
   * @example
   * // To adjust the Bing maps regional setting.
   * let bing = new BingMapsLayer({
   *   key: "~~~~~~~~~~~~~~~~~~~~~~~~ Bing maps key ~~~~~~~~~~~~~~~~~~~~~~~~~",
   *   region: "NZ"
   * });
   */
  accessor region: BingMapsRegion | null | undefined;
